import React from "react";
import { ArrowRight } from "lucide-react";

const disciplines = [
    {
        id: "01",
        title: "Structural & Layout",
        description: "A complete main-floor gut. We removed three load-bearing walls and engineered massive steel support beams to create a completely uninterrupted, open-concept sightline from the front door to the rear glass.",
        // A single, massive, full-width photo works best here to show the scale of the room
        images: [
            "https://images.unsplash.com/photo-1600585154340-be6161a56a0c?q=80&w=2560&auto=format&fit=crop",
        ],
    },
    {
        id: "02",
        title: "Custom Millwork",
        description: "The kitchen is anchored by floor-to-ceiling custom cabinetry with seamlessly integrated, panel-ready appliances. The continuous-vein marble waterfall island was installed with millimeter-tight tolerances.",
        // A two-column grid works perfectly here to show off specific cabinetry/island angles
        images: [
            "https://images.unsplash.com/photo-1556910103-1c02745a8e1e?q=80&w=1200&auto=format&fit=crop",
            "https://images.unsplash.com/photo-1584622650111-993a426fbf0a?q=80&w=1200&auto=format&fit=crop",
        ],
    },
    {
        id: "03",
        title: "Millimeter Finishes",
        description: "Commercial discipline means no sloppy transitions. We obsess over the micro-details: the flush baseboard reveals, the seamless tile-to-hardwood grout lines, and perfectly aligned lighting trims.",
        // Back to a single wide shot, or a tight close-up of a premium detail
        images: [
            "https://images.unsplash.com/photo-1588854337221-4cfb8321fb7a?q=80&w=2560&auto=format&fit=crop",
        ],
    },
];

export default function ProjectStudy() {
    return (
        <section className="bg-brand-ink text-white py-24 md:py-32">
            <div className="max-w-7xl mx-auto px-6 md:px-10">

                {/* Header Section */}
                <div className="mb-20 md:mb-32">
                    <div className="flex items-center gap-3 mb-6">
                        <span className="block w-10 h-px bg-brand-accent" />
                        <span className="text-xs tracking-[0.28em] uppercase text-white/55 font-medium">
                            Case Study
                        </span>
                    </div>
                    <h2 className="font-display text-4xl md:text-5xl lg:text-7xl font-medium tracking-tighter mb-8">
                        The Sanford Build.
                    </h2>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-6 border-t border-white/10 pt-8 max-w-3xl">
                        <div>
                            <div className="text-xs uppercase tracking-[0.2em] text-white/45 mb-1.5">Scope</div>
                            <div className="text-sm font-medium text-white/90">Full Interior Gut</div>
                        </div>
                        <div>
                            <div className="text-xs uppercase tracking-[0.2em] text-white/45 mb-1.5">Timeline</div>
                            <div className="text-sm font-medium text-white/90">14 Weeks</div>
                        </div>
                        <div>
                            <div className="text-xs uppercase tracking-[0.2em] text-white/45 mb-1.5">Location</div>
                            <div className="text-sm font-medium text-white/90">Springwater, ON</div>
                        </div>
                    </div>
                </div>

                {/* The Discipline Breakdown */}
                <div className="space-y-24 md:space-y-32">
                    {disciplines.map((section) => (
                        <div key={section.id} className="group">

                            {/* Section Text Header */}
                            <div className="flex flex-col md:flex-row gap-6 md:gap-16 mb-10 md:mb-14">
                                <div className="md:w-1/3">
                                    <div className="text-brand-accent font-display text-xl mb-2">{section.id} //</div>
                                    <h3 className="text-3xl md:text-4xl font-display font-medium text-white/90">
                                        {section.title}
                                    </h3>
                                </div>
                                <div className="md:w-2/3 md:pt-8">
                                    <p className="text-lg leading-relaxed text-white/70 max-w-2xl">
                                        {section.description}
                                    </p>
                                </div>
                            </div>

                            {/* Dynamic Image Grid based on how many photos you put in the array */}
                            <div className={`grid gap-4 md:gap-6 ${section.images.length === 1 ? 'grid-cols-1' : 'grid-cols-1 md:grid-cols-2'}`}>
                                {section.images.map((img, idx) => (
                                    <div key={idx} className="relative aspect-video md:aspect-[4/3] overflow-hidden bg-brand-charcoal">
                                        <img
                                            src={img}
                                            alt={`${section.title} Detail ${idx + 1}`}
                                            loading="lazy"
                                            className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 hover:scale-105"
                                        />
                                    </div>
                                ))}
                            </div>

                        </div>
                    ))}
                </div>

                {/* Footer CTA */}
                <div className="mt-24 pt-12 border-t border-white/10 flex justify-center">
                    <button className="group inline-flex items-center gap-3 text-sm font-bold tracking-[0.2em] uppercase text-brand-accent hover:text-white transition-colors">
                        View All 30 Project Photos
                        <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>

            </div>
        </section>
    );
}
